//! Database seeder binary for module: bucket
//!
//! Generated by backbone-schema. Do not edit manually.
//!
//! Run with: cargo run --bin bucket-seeder
//! Or via CLI: backbone seed run --module bucket
//!
//! This binary runs all registered seeders in order.

use anyhow::Result;
use sqlx::postgres::PgPoolOptions;
use std::env;

// Import seeders
use backbone_bucket::seeders::SeedAccessLogSeeder;
use backbone_bucket::seeders::SeedBucketSeeder;
use backbone_bucket::seeders::SeedContentHashSeeder;
use backbone_bucket::seeders::SeedConversionJobSeeder;
use backbone_bucket::seeders::SeedFileCommentSeeder;
use backbone_bucket::seeders::SeedFileLockSeeder;
use backbone_bucket::seeders::SeedFileShareSeeder;
use backbone_bucket::seeders::SeedFileVersionSeeder;
use backbone_bucket::seeders::SeedProcessingJobSeeder;
use backbone_bucket::seeders::SeedStoredFileSeeder;
use backbone_bucket::seeders::SeedThumbnailSeeder;
use backbone_bucket::seeders::SeedUploadSessionSeeder;
use backbone_bucket::seeders::SeedUserQuotaSeeder;
use backbone_bucket::seeders::Seeder;

#[tokio::main]
async fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();
    let force = args.iter().any(|a| a == "--force");
    let filter: Option<&str> = args.iter()
        .skip(1)
        .find(|a| !a.starts_with("-"))
        .map(|s| s.as_str());

    let database_url = env::var("DATABASE_URL")
        .expect("DATABASE_URL must be set");

    println!("Connecting to database...");

    let pool = PgPoolOptions::new()
        .max_connections(5)
        .connect(&database_url)
        .await?;

    println!("Connected to database");
    println!();
    println!("Running seeders for module: bucket");
    println!();

    // Register seeders in order
    let mut seeders: Vec<Box<dyn Seeder + Send + Sync>> = Vec::new();
    seeders.push(Box::new(SeedAccessLogSeeder::new()));
    seeders.push(Box::new(SeedBucketSeeder::new()));
    seeders.push(Box::new(SeedContentHashSeeder::new()));
    seeders.push(Box::new(SeedConversionJobSeeder::new()));
    seeders.push(Box::new(SeedFileCommentSeeder::new()));
    seeders.push(Box::new(SeedFileLockSeeder::new()));
    seeders.push(Box::new(SeedFileShareSeeder::new()));
    seeders.push(Box::new(SeedFileVersionSeeder::new()));
    seeders.push(Box::new(SeedProcessingJobSeeder::new()));
    seeders.push(Box::new(SeedStoredFileSeeder::new()));
    seeders.push(Box::new(SeedThumbnailSeeder::new()));
    seeders.push(Box::new(SeedUploadSessionSeeder::new()));
    seeders.push(Box::new(SeedUserQuotaSeeder::new()));

    // Sort by order
    seeders.sort_by_key(|s| s.order());

    // Run seeders
    for seeder in &seeders {
        let name = seeder.name();

        // Apply filter if specified
        if let Some(f) = filter {
            if !name.contains(f) {
                continue;
            }
        }

        if force {
            println!("   Running {}...", name);
            seeder.run(&pool).await?;
            println!("   {} completed", name);
        } else {
            println!("   Checking {}...", name);
            if seeder.should_run(&pool).await? {
                println!("   Running {}...", name);
                seeder.run(&pool).await?;
                println!("   {} completed", name);
            } else {
                println!("   {} already applied, skipping", name);
            }
        }
    }

    println!();
    println!("All seeders completed successfully!");

    Ok(())
}
